export const scene: DialogueEntry[] = [
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "22:58。", background: Background.Chapter_7_Ch7_Act17_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "後台半封閉設備通道的門，開了。", background: Background.Chapter_7_Ch7_Act17_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "不是被人推開的。是電子鎖「喀」一聲鬆開，門板向內退了半寸，像有人從遠處按下了什麼。那聲「喀」很輕，輕到幾乎被暴雨和禮堂裡漫出來的嗡鳴吞掉。但顧言聽見了。因為他一直在等這一聲。", background: Background.Chapter_7_Ch7_Act17_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）開了。", background: Background.Chapter_7_Ch7_Act17_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）22:58。和上一輪一樣。", background: Background.Chapter_7_Ch7_Act17_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）門開了。", background: Background.Chapter_7_Ch7_Act17_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他不在最佳位置。", background: Background.Chapter_7_Ch7_Act17_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "上一輪，他是隔著側門那塊窄玻璃看見一切的。這一輪，他繞到了設備通道外側的轉角——離門更近，但視線被一排堆疊的器材箱擋住了一半。許星棠在通道另一端，靠近直播控制台的小門。她比他更靠內，但她面朝備份線接口，背對著這扇剛開的門。", background: Background.Chapter_7_Ch7_Act17_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "韓越不在。", background: Background.Chapter_7_Ch7_Act17_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "韓越在 22:52 被擋在舞台側門外。通行卡螢幕上跳著「閉幕清場，權限重整」。他進不來。", background: Background.Chapter_7_Ch7_Act17_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）三個人。三個位置。沒有一個人站在能直接攔住那扇門的地方。", background: Background.Chapter_7_Ch7_Act17_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯和上一輪一樣。", background: Background.Chapter_7_Ch7_Act17_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）但我不一樣了。", background: Background.Chapter_7_Ch7_Act17_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "一個人影從門的暗處走進來。", background: Background.Chapter_7_Ch7_Act17_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "黑色雨衣。帽沿壓得很低。和第五章那一次一模一樣——同樣的寬大雨衣，同樣的帽沿角度，同樣的直線步伐。如果不是已經經歷過一輪，顧言會以為自己在看同一幅畫面重播。", background: Background.Chapter_7_Ch7_Act17_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "但這一次，他不只是看。", background: Background.Chapter_7_Ch7_Act17_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "這一次，他知道該看哪裡。", background: Background.Chapter_7_Ch7_Act17_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "第一樣東西。袖口。", background: Background.Chapter_7_Ch7_Act17_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "黑雨衣的左袖口在伸手推門框的時候往上帶了一寸。只有一寸。在第五章，顧言沒有注意到這個——他當時隔著玻璃，距離太遠，光太暗，他只看見一個輪廓。但這一次他離得近了，而且他知道要找什麼。", background: Background.Chapter_7_Ch7_Act17_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "袖口下面，露出一截深藍色的布料。不是雨衣的內襯。是制服。合身的、深藍色的、肩線挺括的——制服。", background: Background.Chapter_7_Ch7_Act17_S1 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）制服。", background: Background.Chapter_7_Ch7_Act17_S1, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）深藍色。肩線。警銜。", background: Background.Chapter_7_Ch7_Act17_S1, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯校慶安保聯絡官的制服。", background: Background.Chapter_7_Ch7_Act17_S1, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "第二樣東西。手腕。", background: Background.Chapter_7_Ch7_Act17_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "那截袖口帶起來的同時，左手腕上露出一隻錶。舊的。銀色的。錶面不大，錶殼邊緣磨得發亮，是那種戴了很多年、已經和手腕長在一起的東西。", background: Background.Chapter_7_Ch7_Act17_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "錶面右下角，有一道裂痕。", background: Background.Chapter_7_Ch7_Act17_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "很細。不仔細看會以為是錶面的反光。但顧言看見了。因為他今天早上 11:30 在禮堂側廊，看見邵叔抬手看錶的時候，就在那隻舊銀錶的右下角看見過同一道裂痕。", background: Background.Chapter_7_Ch7_Act17_S1 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯銀錶。", background: Background.Chapter_7_Ch7_Act17_S1, portrait: Portrait.GuYan_Scared },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）右下角。裂痕。", background: Background.Chapter_7_Ch7_Act17_S1, portrait: Portrait.GuYan_Scared },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）今天早上。禮堂側廊。他抬手看時間的時候——", background: Background.Chapter_7_Ch7_Act17_S1, portrait: Portrait.GuYan_Scared },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）同一隻錶。", background: Background.Chapter_7_Ch7_Act17_S1, portrait: Portrait.GuYan_Scared },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "第三樣東西。走路的樣子。", background: Background.Chapter_7_Ch7_Act17_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "那個人影進門之後，沒有直奔許星棠。他先停了一下。很短。不到一秒。他的頭向左轉了十五度，再向右轉了十五度——掃了兩側的死角。然後才邁步，走進設備通道。", background: Background.Chapter_7_Ch7_Act17_S1 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯", background: Background.Chapter_7_Ch7_Act17_S1, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）那個動作。", background: Background.Chapter_7_Ch7_Act17_S1, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）先看左右死角。再進。", background: Background.Chapter_7_Ch7_Act17_S1, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）不是學生會做的。不是老師會做的。不是行政人員會做的。", background: Background.Chapter_7_Ch7_Act17_S1, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）是巡邏的人。是受過訓練的、習慣在進入封閉空間前清查視線盲區的人。", background: Background.Chapter_7_Ch7_Act17_S1, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）是警察。", background: Background.Chapter_7_Ch7_Act17_S1, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "三樣東西疊在一起。", background: Background.Chapter_7_Ch7_Act17_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "制服。銀錶。巡邏習慣。", background: Background.Chapter_7_Ch7_Act17_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "它們不是證據。暴雨聲太大，光線太暗，顧言的手機鏡頭從這個角度只能拍到一團模糊的黑色。他沒有錄到清楚的影像。許星棠在通道另一端，她可能聽見顧言接下來會喊什麼，但她不一定能聽見對方的回應。韓越被擋在外面，連看都看不到。", background: Background.Chapter_7_Ch7_Act17_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "但顧言不需要證據了。", background: Background.Chapter_7_Ch7_Act17_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他已經知道答案了。他從 22:05 在醫務室看見二號冰敷櫃被拉出來、紅色盤點標籤貼在櫃門內側的那一刻，就已經知道了。他只是不願意承認。", background: Background.Chapter_7_Ch7_Act17_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "現在他不能不承認了。", background: Background.Chapter_7_Ch7_Act17_S1 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯", background: Background.Chapter_7_Ch7_Act17_S1, portrait: Portrait.GuYan_Scared },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）不是他。", background: Background.Chapter_7_Ch7_Act17_S1, portrait: Portrait.GuYan_Scared },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）不要是他。", background: Background.Chapter_7_Ch7_Act17_S1, portrait: Portrait.GuYan_Scared },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯", background: Background.Chapter_7_Ch7_Act17_S1, portrait: Portrait.GuYan_Scared },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）是他。", background: Background.Chapter_7_Ch7_Act17_S1, portrait: Portrait.GuYan_Trembling },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "那個人影已經走了三步。再走兩步，就會走到許星棠身後。", background: Background.Chapter_7_Ch7_Act17_S1 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）喊他。", background: Background.Chapter_7_Ch7_Act17_S1, portrait: Portrait.GuYan_Trembling },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）喊他的名字。如果他停——", background: Background.Chapter_7_Ch7_Act17_S1, portrait: Portrait.GuYan_Trembling },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）如果他回頭——", background: Background.Chapter_7_Ch7_Act17_S1, portrait: Portrait.GuYan_Trembling },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯就是他了。", background: Background.Chapter_7_Ch7_Act17_S1, portrait: Portrait.GuYan_Trembling },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "顧言張嘴。", background: Background.Chapter_7_Ch7_Act17_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "聲音從喉嚨裡出來的時候，他自己都不確定能不能穿過這條走廊的噪音。暴雨打在高窗上。禮堂裡的音樂開始漸強——倒數前的鼓點。掌聲一陣一陣地湧過來，像潮水。", background: Background.Chapter_7_Ch7_Act17_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他喊了。", background: Background.Chapter_7_Ch7_Act17_S1 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "邵叔。", background: Background.Chapter_7_Ch7_Act17_S1, portrait: Portrait.GuYan_Trembling },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "不是喊。是說。聲音壓得很低，低到幾乎只有自己聽得見。但那兩個字的重量，比他這一輪說過的所有話加起來都重。", background: Background.Chapter_7_Ch7_Act17_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "黑雨衣的人影停住了。", background: Background.Chapter_7_Ch7_Act17_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "停得很乾脆。像踩到了一條線。不是被嚇到的那種停——沒有回頭、沒有舉手、沒有任何多餘的動作。只是腳步斷了。整個人定在原地。", background: Background.Chapter_7_Ch7_Act17_S1 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯他停了。", background: Background.Chapter_7_Ch7_Act17_S1, portrait: Portrait.GuYan_Shocked },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）他聽見了。", background: Background.Chapter_7_Ch7_Act17_S1, portrait: Portrait.GuYan_Shocked },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）他知道這個名字是在叫他。", background: Background.Chapter_7_Ch7_Act17_S1, portrait: Portrait.GuYan_Shocked },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "禮堂裡的聲音在同一秒炸開。", background: Background.Chapter_7_Ch7_Act17_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "主持人的聲音經過擴音、經過水泥牆、傳到這條走廊的時候已經變成了一個模糊的、帶金屬味的影子——但每一個字都還聽得清。", background: Background.Chapter_7_Ch7_Act17_S1 },
    { characterId: CharacterId.Mc, character: "主持人", dialogue: "各位來賓——", background: Background.Chapter_7_Ch7_Act17_S1, portrait: Portrait.Mc_Base },
    { characterId: CharacterId.Mc, character: "主持人", dialogue: "百年鳴海——", background: Background.Chapter_7_Ch7_Act17_S1, portrait: Portrait.Mc_Base },
    { characterId: CharacterId.Mc, character: "主持人", dialogue: "倒數二十秒——", background: Background.Chapter_7_Ch7_Act17_S1, portrait: Portrait.Mc_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "掌聲。暴雨。鼓點。三種聲音疊在一起，像三層厚布同時蓋上來。走廊裡什麼都聽不清了。", background: Background.Chapter_7_Ch7_Act17_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "但在那三層布的縫隙裡——", background: Background.Chapter_7_Ch7_Act17_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "在掌聲最響的那一拍的間隙、在暴雨砸下來的兩陣之間的半秒安靜裡——", background: Background.Chapter_7_Ch7_Act17_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "顧言聽見了一個聲音。", background: Background.Chapter_7_Ch7_Act17_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "很輕。很低。低到像從胸腔裡震出來的，不是從嘴裡說出來的。如果顧言不是站在離那人影不到五步的地方，如果他的耳朵不是從剛才起就一直支著、一直支著、把所有聲音都收進去——他不會聽見。", background: Background.Chapter_7_Ch7_Act17_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "但他聽見了。", background: Background.Chapter_7_Ch7_Act17_S1 },
    { characterId: CharacterId.BlackRaincoat, character: "黑雨衣", dialogue: "小言，別逼我。", background: Background.Chapter_7_Ch7_Act17_S1, portrait: Portrait.BlackRaincoat_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "四個字。", background: Background.Chapter_7_Ch7_Act17_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "「小言」——沒有人這樣叫他。除了一個人。從他七歲開始，從他父親被帶走那天開始，那個人就這樣叫他。小言。帶著渾厚的、像父親一樣的穿透力。每一次都帶著笑。每一次都讓他以為自己是被保護的。", background: Background.Chapter_7_Ch7_Act17_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "「別逼我」——這三個字，他從來沒有聽過。但那個聲音的質地、那個壓低的語氣、那種不急不慢的、像在下命令的穩——他太熟了。", background: Background.Chapter_7_Ch7_Act17_S1 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯", background: Background.Chapter_7_Ch7_Act17_S1, portrait: Portrait.GuYan_Trembling },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）是他。", background: Background.Chapter_7_Ch7_Act17_S1, portrait: Portrait.GuYan_Trembling },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）是他。", background: Background.Chapter_7_Ch7_Act17_S1, portrait: Portrait.GuYan_Trembling },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯真的是他。", background: Background.Chapter_7_Ch7_Act17_S1, portrait: Portrait.GuYan_Trembling },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "黑雨衣的人影沒有回頭。", background: Background.Chapter_7_Ch7_Act17_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他停了不到兩秒。然後，他繼續走了。向許星棠的方向。步伐沒有變。速度沒有變。像剛才那句話不是說給顧言聽的——是說給自己聽的。像他在告訴自己：已經沒有回頭的路了。", background: Background.Chapter_7_Ch7_Act17_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "顧言站在原地。", background: Background.Chapter_7_Ch7_Act17_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "手在抖。不是冷的抖。是什麼東西在胸腔裡裂開了，裂縫裡漏出來的震動傳到了指尖。", background: Background.Chapter_7_Ch7_Act17_S1 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）七年。", background: Background.Chapter_7_Ch7_Act17_S1, portrait: Portrait.GuYan_Trembling },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）他照顧了我七年。", background: Background.Chapter_7_Ch7_Act17_S1, portrait: Portrait.GuYan_Trembling },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）外套太薄。吃了沒。胃受得了嗎。", background: Background.Chapter_7_Ch7_Act17_S1, portrait: Portrait.GuYan_Trembling },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯小言。", background: Background.Chapter_7_Ch7_Act17_S1, portrait: Portrait.GuYan_Trembling },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）他叫我小言的時候，我以為——", background: Background.Chapter_7_Ch7_Act17_S1, portrait: Portrait.GuYan_Trembling },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）我以為他是唯一一個——", background: Background.Chapter_7_Ch7_Act17_S1, portrait: Portrait.GuYan_Trembling },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他沒有把那句話想完。", background: Background.Chapter_7_Ch7_Act17_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "因為他想不完。因為如果他把它想完了，他就會站不住。", background: Background.Chapter_7_Ch7_Act17_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "禮堂裡的倒數聲繼續。", background: Background.Chapter_7_Ch7_Act17_S1 },
    { characterId: CharacterId.Mc, character: "主持人", dialogue: "——十五——", background: Background.Chapter_7_Ch7_Act17_S1, portrait: Portrait.Mc_Base },
    { characterId: CharacterId.Mc, character: "主持人", dialogue: "——十四——", background: Background.Chapter_7_Ch7_Act17_S1, portrait: Portrait.Mc_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "掌聲一陣比一陣響。暴雨一陣比一陣急。黑雨衣的人影離許星棠只剩三步。", background: Background.Chapter_7_Ch7_Act17_S1 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯", background: Background.Chapter_7_Ch7_Act17_S1, portrait: Portrait.GuYan_Trembling },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）動。", background: Background.Chapter_7_Ch7_Act17_S1, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）現在。", background: Background.Chapter_7_Ch7_Act17_S1, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）不能站在這裡。", background: Background.Chapter_7_Ch7_Act17_S1, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）不能讓他走到她面前。", background: Background.Chapter_7_Ch7_Act17_S1, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "顧言的腳動了。", background: Background.Chapter_7_Ch7_Act17_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "不是想好了才動的。是身體比腦子快。和他第五章衝向側門的時候一樣——沒有想。身體先走了。", background: Background.Chapter_7_Ch7_Act17_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "但這一次不同。", background: Background.Chapter_7_Ch7_Act17_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "第五章，他是隔著一扇鎖死的門，拍、撞、喊，什麼都做不了。", background: Background.Chapter_7_Ch7_Act17_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "這一次，門是開的。通道是通的。他離那個人影只有五步。", background: Background.Chapter_7_Ch7_Act17_S1 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）這一次我知道他是誰了。", background: Background.Chapter_7_Ch7_Act17_S1, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）這一次我知道危機在哪裡了。", background: Background.Chapter_7_Ch7_Act17_S1, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯這一次，我不站在門外了。", background: Background.Chapter_7_Ch7_Act17_S1, portrait: Portrait.GuYan_Determined },
];
